"use client";

import { useState, use } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { ProductService } from "@/services/product.service";
import { CartService, WishlistService } from "@/services/cart.service";
import Link from "next/link";
import Image from "next/image";
import { motion } from "framer-motion";
import { Star, ShoppingCart, Heart, Loader2, Filter } from "lucide-react";
import toast from "react-hot-toast";
import { Product } from "@/types/product";

export default function ProductsPage({ searchParams }: { searchParams: Promise<{ category?: string }> }) {
  const [page, setPage] = useState(1);
  const [sort, setSort] = useState("-createdAt");
  
  const resolvedSearchParams = use(searchParams);
  const categoryId = resolvedSearchParams?.category;

  const { data: categories } = useQuery({
    queryKey: ["categories"],
    queryFn: ProductService.getCategories,
  });

  const { data: productsData, isLoading } = useQuery({
    queryKey: ["products", page, sort, categoryId],
    queryFn: () => ProductService.getProducts(page, 16, sort, categoryId),
  });

  return (
    <div className="bg-slate-50 dark:bg-slate-950 flex-1 py-12">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        
        {/* Header & Filters */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4 bg-white dark:bg-slate-900 p-4 rounded-xl shadow-sm border border-slate-200 dark:border-slate-800">
          <div>
            <h1 className="text-2xl font-bold text-slate-900 dark:text-white">All Products</h1>
            <p className="text-sm text-slate-500">Showing {productsData?.data.length || 0} results</p>
          </div>

          <div className="flex items-center gap-4 w-full md:w-auto">
            <div className="flex items-center gap-2">
              <Filter className="w-5 h-5 text-slate-500" />
              <select 
                value={categoryId || ""} 
                onChange={(e) => {
                  window.location.href = `/products${e.target.value ? `?category=${e.target.value}` : ""}`;
                }}
                className="bg-slate-50 dark:bg-slate-800 border border-slate-300 dark:border-slate-700 text-slate-900 dark:text-white text-sm rounded-lg focus:ring-orange-500 focus:border-orange-500 block p-2.5"
              >
                <option value="">All Categories</option>
                {categories?.map((c) => (
                  <option key={c._id} value={c._id}>{c.name}</option>
                ))}
              </select>
            </div>

            <select 
              value={sort} 
              onChange={(e) => setSort(e.target.value)}
              className="bg-slate-50 dark:bg-slate-800 border border-slate-300 dark:border-slate-700 text-slate-900 dark:text-white text-sm rounded-lg focus:ring-orange-500 focus:border-orange-500 block p-2.5"
            >
              <option value="-createdAt">Newest First</option>
              <option value="+price">Price: Low to High</option>
              <option value="-price">Price: High to Low</option>
              <option value="-ratingsAverage">Top Rated</option>
            </select>
          </div>
        </div>

        {/* Product Grid */}
        {isLoading ? (
          <div className="flex justify-center items-center h-64">
            <Loader2 className="w-12 h-12 animate-spin text-orange-600" />
          </div>
        ) : (
          <>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
              {productsData?.data.map((product) => (
                <ProductCard key={product._id} product={product} />
              ))}
            </div>

            {/* Pagination */}
            {productsData?.metadata && productsData.metadata.numberOfPages > 1 && (
              <div className="flex justify-center mt-12 gap-2">
                <button 
                  onClick={() => setPage((p) => Math.max(1, p - 1))}
                  disabled={page === 1}
                  className="px-4 py-2 border border-slate-300 dark:border-slate-700 rounded-md disabled:opacity-50 hover:bg-slate-100 dark:hover:bg-slate-800 transition"
                >
                  Previous
                </button>
                <span className="px-4 py-2 font-medium">Page {page} of {productsData.metadata.numberOfPages}</span>
                <button 
                  onClick={() => setPage((p) => Math.min(productsData.metadata.numberOfPages, p + 1))}
                  disabled={page === productsData.metadata.numberOfPages}
                  className="px-4 py-2 border border-slate-300 dark:border-slate-700 rounded-md disabled:opacity-50 hover:bg-slate-100 dark:hover:bg-slate-800 transition"
                >
                  Next
                </button>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

function ProductCard({ product }: { product: Product }) {
  const queryClient = useQueryClient();

  const { mutate: addToCart, isPending: isAddingToCart } = useMutation({
    mutationFn: () => CartService.addToCart(product._id),
    onSuccess: () => {
      toast.success(`"${product.title}" added to cart!`);
      queryClient.invalidateQueries({ queryKey: ["cart"] });
    },
    onError: () => {
      toast.error("Please login to add items to the cart.");
    },
  });

  const { mutate: addToWishlist, isPending: isAddingToWishlist } = useMutation({
    mutationFn: () => WishlistService.addToWishlist(product._id),
    onSuccess: () => {
      toast.success(`"${product.title}" added to wishlist!`);
      queryClient.invalidateQueries({ queryKey: ["wishlist"] });
    },
    onError: () => {
      toast.error("Please login to add items to the wishlist.");
    },
  });

  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.95 }}
      animate={{ opacity: 1, scale: 1 }}
      className="group flex flex-col bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300 relative"
    >
      <button
        onClick={() => addToWishlist()}
        disabled={isAddingToWishlist}
        className="absolute top-3 right-3 z-10 p-2 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md rounded-full shadow-sm text-slate-400 hover:text-red-500 hover:bg-white transition-colors disabled:opacity-50"
      >
        {isAddingToWishlist ? <Loader2 className="w-5 h-5 animate-spin" /> : <Heart className="w-5 h-5" />}
      </button>

      <Link href={`/products/${product._id}`} className="block relative aspect-square overflow-hidden bg-slate-100 dark:bg-slate-800">
        <Image
          src={product.imageCover}
          alt={product.title}
          fill
          className="object-cover group-hover:scale-105 transition-transform duration-500"
          sizes="(max-width: 640px) 100vw, (max-width: 1024px) 50vw, 25vw"
        />
      </Link>

      <div className="p-5 flex flex-col flex-1">
        <span className="text-xs font-bold text-orange-600 uppercase tracking-wider mb-2">{product.category.name}</span>
        <Link href={`/products/${product._id}`}>
          <h3 className="font-semibold text-slate-900 dark:text-white text-lg line-clamp-1 mb-2 group-hover:text-orange-600 transition-colors">
            {product.title}
          </h3>
        </Link>

        <div className="flex items-center gap-1 mb-4">
          <Star className="w-4 h-4 fill-amber-400 text-amber-400" />
          <span className="text-sm font-medium text-slate-700 dark:text-slate-300">{product.ratingsAverage}</span>
        </div>

        <div className="mt-auto flex items-center justify-between">
          <span className="font-bold text-xl text-slate-900 dark:text-white">EGP {product.price}</span>
          <button
            onClick={() => addToCart()}
            disabled={isAddingToCart}
            className="p-3 bg-slate-900 dark:bg-slate-800 text-white rounded-xl hover:bg-orange-600 transition-colors shadow-sm active:scale-95 disabled:opacity-50"
          >
            {isAddingToCart ? <Loader2 className="w-5 h-5 animate-spin" /> : <ShoppingCart className="w-5 h-5" />}
          </button>
        </div>
      </div>
    </motion.div>
  );
}
